#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IDX(i,j,dim) ((i)*(dim) + (j))
#define LIDX(i,j)    ((i)*BLOCK_SIZE + (j))

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);

    for (int j = 0; j < BLOCK_SIZE; j++) {
        shadow[LIDX(tx, j)] = m[IDX(offset + tx, offset + j, matrix_dim)];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        if (tx == i) {
            for (int j = i; j < BLOCK_SIZE; j++) {
                float v = shadow[LIDX(i, j)];
                for (int k = 0; k < i; k++) {
                    v -= shadow[LIDX(i, k)] * shadow[LIDX(k, j)];
                }
                shadow[LIDX(i, j)] = v;
            }

            float temp = 1.0f / shadow[LIDX(i, i)];
            for (int j = i + 1; j < BLOCK_SIZE; j++) {
                float v = shadow[LIDX(j, i)];
                for (int k = 0; k < i; k++) {
                    v -= shadow[LIDX(j, k)] * shadow[LIDX(k, i)];
                }
                shadow[LIDX(j, i)] = v * temp;
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int j = 0; j < BLOCK_SIZE; j++) {
        m[IDX(offset + tx, offset + j, matrix_dim)] = shadow[LIDX(tx, j)];
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    int tx = (int)get_local_id(0);
    int b = (int)get_group_id(0);  // chunk index

    int j_global = offset + BLOCK_SIZE * (b + 1);
    int i_global = offset + BLOCK_SIZE * (b + 1);

    if (tx < BLOCK_SIZE) {
        int r = tx;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            dia[LIDX(r, j)]      = m[IDX(offset + r, offset + j, matrix_dim)];
            peri_row[LIDX(r, j)] = m[IDX(offset + r, j_global + j, matrix_dim)];
        }
    } else {
        int r = tx - BLOCK_SIZE;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            peri_col[LIDX(r, j)] = m[IDX(i_global + r, offset + j, matrix_dim)];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        int i = tx;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += dia[LIDX(i, k)] * peri_row[LIDX(k, j)];
            }
            peri_row[LIDX(i, j)] -= sum;
        }
    } else {
        int i = tx - BLOCK_SIZE;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += peri_col[LIDX(i, k)] * dia[LIDX(k, j)];
            }
            peri_col[LIDX(i, j)] = (peri_col[LIDX(i, j)] - sum) / dia[LIDX(j, j)];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        int r = tx;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            m[IDX(offset + r, j_global + j, matrix_dim)] = peri_row[LIDX(r, j)];
        }
    } else {
        int r = tx - BLOCK_SIZE;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            m[IDX(i_global + r, offset + j, matrix_dim)] = peri_col[LIDX(r, j)];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *temp_top,
                           __local float *temp_left,
                           int matrix_dim,
                           int offset)
{
    int lx = (int)get_local_id(0);   // col in block
    int ly = (int)get_local_id(1);   // row in block
    int bx = (int)get_group_id(0);   // block col
    int by = (int)get_group_id(1);   // block row

    int i_global = offset + BLOCK_SIZE * (by + 1);
    int j_global = offset + BLOCK_SIZE * (bx + 1);

    temp_top[LIDX(ly, lx)]  = m[IDX(offset + ly,     j_global + lx, matrix_dim)];
    temp_left[LIDX(ly, lx)] = m[IDX(i_global + ly,   offset + lx,   matrix_dim)];
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[LIDX(ly, k)] * temp_top[LIDX(k, lx)];
    }

    int gi = i_global + ly;
    int gj = j_global + lx;
    m[IDX(gi, gj, matrix_dim)] -= sum;
}
